await configureWorkflow({
    name: "API Server",
    command: "PORT=8080 pnpm --filter @workspace/api-server run dev",
    waitForPort: 8080,
    outputType: "console",
    autoStart: true
});
console.log("API Server workflow updated");

// Fix Frontend - use port 5000 (supported), pass as PORT env
