    21→const ScreenContext = createContext<ScreenContextValue | null>(null);
    22→
    23→export function ScreenProvider({ children }: { children: ReactNode }) {
    24→  const [currentScreen, setCurrentScreen] = useState<Screen>("landing");
    25→  const [previousScreen, setPreviousScreen] = useState<Screen | null>(null);
    26→  const [showNav, setShowNav] = useState(false);
    27→  const [hasLeftLanding, setHasLeftLanding] = useState(false);
    28→
    29→  const setScreen = (name: Screen) => {
    30→    setPreviousScreen(currentScreen);
    31→    setCurrentScreen(name);
    32→  };
    33→
    34→  // Once user has left landing, redirect any attempt to return back to prospect-chat
    35→  useEffect(() => {
    36→    if (hasLeftLanding && currentScreen === "landing") {
    37→      setCurrentScreen("prospect-chat");
    38→    }
    39→  }, [currentScreen, hasLeftLanding]);
    40→
    41→  return (
    42→    <ScreenContext.Provider value={{ currentScreen, setScreen, previousScreen, showNav, setShowNav, hasLeftLanding, setHasLeftLanding }}>
    43→      {children}
    44→    </ScreenContext.Provider>
    45→  );
    46→}
