              overflow: "hidden",
            }}
          >
            <div
              style={{
                display: "flex",
                alignItems: "center",
                justifyContent: "space-between",
                padding: "14px 16px",
                borderBottom: "1px solid rgba(255,255,255,0.06)",
              }}
            >
              <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                <Clock size={14} style={{ color: "var(--db-accent)" }} />
                <span style={{ fontSize: 13, fontWeight: 600, color: "var(--db-text-primary)" }}>Audit Trail</span>
                <span style={{ fontSize: 10, color: "var(--db-text-secondary)" }}>{lead.auditEvents.length} events</span>
              </div>
              <button
                onClick={() => setAuditOpen((v) => !v)}
                style={{
                  fontSize: 11,
                  fontWeight: 600,
                  color: "var(--db-accent)",
                  background: "rgba(0,212,255,0.08)",
                  border: "1px solid rgba(0,212,255,0.2)",
                  borderRadius: 6,
                  padding: "4px 10px",
                  cursor: "pointer",
                }}
              >
                {auditOpen ? "Collapse" : "Expand All"}
              </button>
            </div>

            {/* Events */}
            <div style={{ padding: "8px 16px 12px", display: "flex", flexDirection: "column", gap: 2 }}>
              {(auditOpen ? lead.auditEvents : lead.auditEvents.slice(-4)).map((ev, i, arr) => (
                <div
                  key={i}
                  style={{
                    display: "flex",
                    alignItems: "flex-start",
                    gap: 10,
                    padding: "8px 10px",
                    borderRadius: 8,
                    background: i === arr.length - 1 ? "rgba(16,185,129,0.04)" : "transparent",
                    border: i === arr.length - 1 ? "1px solid rgba(16,185,129,0.12)" : "1px solid transparent",
                  }}
                >
                  <div style={{ display: "flex", flexDirection: "column", alignItems: "center", paddingTop: 3, flexShrink: 0 }}>
                    <div style={{ width: 7, height: 7, borderRadius: "50%", background: ev.tagColor, boxShadow: `0 0 5px ${ev.tagColor}80` }} />
                    {i < arr.length - 1 && <div style={{ width: 1, height: 18, background: "rgba(255,255,255,0.07)", marginTop: 3 }} />}
                  </div>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 7, marginBottom: 2, flexWrap: "wrap" }}>
                      <span style={{ fontSize: 12, fontWeight: 600, color: "var(--db-text-primary)" }}>{ev.actor}</span>
                      <span style={{ fontSize: 9, fontWeight: 600, letterSpacing: "0.06em", padding: "1px 6px", borderRadius: 20, background: `${ev.tagColor}18`, border: `1px solid ${ev.tagColor}40`, color: ev.tagColor }}>
                        {ev.tag}
                      </span>
                    </div>
                    <div style={{ fontSize: 11.5, color: "var(--db-text-secondary)", lineHeight: 1.4 }}>{ev.action}</div>
                  </div>
                  <div style={{ fontSize: 10, color: "rgba(136,146,176,0.4)", flexShrink: 0, paddingTop: 2, whiteSpace: "nowrap" }}>
                    {ev.time}
                  </div>
                </div>
              ))}

              {!auditOpen && lead.auditEvents.length > 4 && (
                <button
                  onClick={() => setAuditOpen(true)}
                  style={{
                    marginTop: 4,
                    fontSize: 11,
                    color: "var(--db-text-secondary)",
                    background: "transparent",
                    border: "none",
                    cursor: "pointer",
                    textAlign: "left",
                    padding: "4px 10px",
                  }}
                >
                  + {lead.auditEvents.length - 4} more events
                </button>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// ── Main Dashboard ────────────────────────────────────────────────────────────
export default function Dashboard() {
  const [selectedLead, setSelectedLead] = useState<Lead | null>(null);
  const [filterStage, setFilterStage] = useState<Lead["stage"] | "All">("All");

  const stageCounts = LEADS.reduce<Record<string, number>>((acc, l) => {
    acc[l.stage] = (acc[l.stage] ?? 0) + 1;
    return acc;
  }, {});

  const filteredLeads = filterStage === "All" ? LEADS : LEADS.filter((l) => l.stage === filterStage);
  const avgScore = Math.round(LEADS.reduce((s, l) => s + l.score, 0) / LEADS.length);
  const confirmedCount = stageCounts["Confirmed"] ?? 0;

  const STAGES: Array<Lead["stage"] | "All"> = ["All", "New", "Qualified", "Routing", "Handoff", "Confirmed"];

  return (
    <>
      {selectedLead && (
        <LeadDetail lead={selectedLead} onClose={() => setSelectedLead(null)} />
      )}

      <div
        style={{
          width: "100%",
          maxWidth: 1000,
          margin: "0 auto",
          padding: "clamp(20px, 3vw, 36px) 16px",
          minHeight: "calc(100dvh - 60px - 44px)",
        }}
      >
        {/* ── Page header ── */}
        <div style={{ marginBottom: 28 }}>
          <div
            style={{
              display: "inline-flex",
              alignItems: "center",
              gap: 6,
              padding: "3px 10px",
              borderRadius: 20,
              marginBottom: 12,
              fontSize: 10,
              fontWeight: 700,
              letterSpacing: "0.1em",
              textTransform: "uppercase",
              color: "var(--db-accent)",
              background: "rgba(0,212,255,0.08)",
              border: "1px solid rgba(0,212,255,0.18)",
            }}
          >
            <TrendingUp size={10} />
            Live Pipeline
          </div>
          <h1
            style={{
              fontFamily: "var(--app-font-serif)",
              fontSize: "clamp(22px, 3.5vw, 32px)",
              fontWeight: 600,
              color: "var(--db-accent)",
              letterSpacing: "-0.01em",
              textShadow: "0 0 28px rgba(0,212,255,0.2)",
              marginBottom: 4,
            }}
          >
            Lead Dashboard
          </h1>
          <p style={{ fontSize: 13, color: "var(--db-text-secondary)" }}>
            All inbound leads · AI-qualified · Click any row to view full brief and audit
          </p>
        </div>

        {/* ── Stats row ── */}
        <div style={{ display: "flex", flexWrap: "wrap", gap: 12, marginBottom: 28 }}>
          <StatCard label="Total Leads" value={LEADS.length} sub="all time" />
          <StatCard label="Confirmed" value={confirmedCount} sub="routed to specialist" color="#10b981" />
          <StatCard label="Avg. Score" value={`${avgScore}%`} sub="AI qualification score" color={scoreColor(avgScore)} />
          <StatCard label="In Pipeline" value={LEADS.length - confirmedCount} sub="active leads" color="#f59e0b" />
        </div>

        {/* ── Stage filter pills ── */}
        <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginBottom: 18 }}>
          {STAGES.map((s) => {
            const active = filterStage === s;
            const count = s === "All" ? LEADS.length : (stageCounts[s] ?? 0);
            const sc = s === "All" ? { color: "var(--db-accent)", bg: "rgba(0,212,255,0.1)", border: "rgba(0,212,255,0.25)" } : stageColor(s as Lead["stage"]);
            return (
              <button
                key={s}
                onClick={() => setFilterStage(s)}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: 6,
                  padding: "5px 14px",
                  borderRadius: 20,
                  fontSize: 12,
                  fontWeight: 600,
                  cursor: "pointer",
                  transition: "all 200ms",
                  background: active ? sc.bg : "rgba(255,255,255,0.03)",
                  border: active ? `1px solid ${sc.border}` : "1px solid rgba(255,255,255,0.08)",
                  color: active ? sc.color : "var(--db-text-secondary)",
                }}
              >
                {s}
                <span
                  style={{
                    fontSize: 10,
                    fontWeight: 700,
                    padding: "1px 6px",
                    borderRadius: 20,
                    background: active ? `${sc.color}22` : "rgba(255,255,255,0.06)",
                    color: active ? sc.color : "var(--db-text-secondary)",
                  }}
                >
                  {count}
                </span>
              </button>
            );
          })}
        </div>

        {/* ── Lead list ── */}
        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
          {filteredLeads.length === 0 ? (
            <div style={{ textAlign: "center", padding: "48px 0", color: "var(--db-text-secondary)", fontSize: 14 }}>
              No leads in this stage
            </div>
          ) : (
            filteredLeads.map((lead) => (
              <LeadRow
                key={lead.id}
                lead={lead}
                onClick={() => setSelectedLead(lead)}
              />
            ))
          )}
        </div>
      </div>
    </>
  );
}

import { useState, useEffect } from "react";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { Toaster } from "@/components/ui/toaster";
import { TooltipProvider } from "@/components/ui/tooltip";
import { ScreenProvider, useScreen, type Screen } from "@/contexts/ScreenContext";
import Landing from "@/screens/Landing";
import ProspectChat from "@/screens/ProspectChat";
import AccountBrief from "@/screens/AccountBrief";
import RoutingDecision from "@/screens/RoutingDecision";
import HandoffOutcome from "@/screens/HandoffOutcome";
import Dashboard from "@/screens/Dashboard";

const queryClient = new QueryClient({
  defaultOptions: {
    queries: { retry: 1, staleTime: 30_000 },
  },
});

const NAV_TABS: { id: Screen; label: string }[] = [
  { id: "dashboard", label: "Dashboard" },
  { id: "prospect-chat", label: "Prospect Chat" },
  { id: "account-brief", label: "Account Brief" },
  { id: "routing", label: "Routing" },
  { id: "handoff", label: "Handoff" },
];

function Header() {
  const { currentScreen, setScreen, hasLeftLanding } = useScreen();
  const [hoveredTab, setHoveredTab] = useState<Screen | null>(null);

  return (
    <header
      className="fixed top-0 left-0 right-0 z-50 flex items-center justify-between px-6"
      style={{
        height: "60px",
        background: "rgba(10, 14, 39, 0.85)",
        backdropFilter: "blur(20px)",
        WebkitBackdropFilter: "blur(20px)",
        borderBottom: "1px solid rgba(0, 212, 255, 0.12)",
      }}
    >
      {/* Logo */}
      <button
        data-testid="button-logo-home"
        onClick={() => setScreen("landing")}
        className="flex-shrink-0 flex items-center gap-2 transition-all duration-300"
        style={{ color: "var(--db-accent)" }}
        onMouseEnter={(e) => {
          (e.currentTarget as HTMLButtonElement).style.filter = "drop-shadow(0 0 8px rgba(0,212,255,0.6))";
        }}
        onMouseLeave={(e) => {
          (e.currentTarget as HTMLButtonElement).style.filter = "none";
        }}
      >
        <div
          className="w-7 h-7 rounded-lg flex items-center justify-center text-xs font-black"
          style={{
            background: "linear-gradient(135deg, rgba(0,212,255,0.3), rgba(0,212,255,0.1))",
            border: "1px solid rgba(0,212,255,0.35)",
            color: "var(--db-accent)",
          }}
        >
          DB
        </div>
        <span
          className="text-xl font-semibold tracking-tight hidden sm:block"
          style={{ fontFamily: "var(--app-font-serif)", color: "var(--db-accent)" }}
        >
          DealBridge <span style={{ color: "var(--db-text-primary)" }}>AI</span>
        </span>
      </button>

      {/* Center tabs — always visible after leaving landing */}
      <nav
        className="hidden md:flex items-center gap-1"
        aria-label="Main navigation"
        style={{
          opacity: hasLeftLanding ? 1 : 0,
          pointerEvents: hasLeftLanding ? "auto" : "none",
          transition: "opacity 300ms ease",
        }}
      >
        {NAV_TABS.map((tab) => {
          const isActive = currentScreen === tab.id;
          const isHovered = hoveredTab === tab.id;
          return (
            <button
              key={tab.id}
              data-testid={`tab-${tab.id}`}
              onClick={() => setScreen(tab.id)}
              onMouseEnter={() => setHoveredTab(tab.id)}
              onMouseLeave={() => setHoveredTab(null)}
              className="relative px-4 py-2 text-sm font-medium rounded-lg transition-all duration-300"
              style={{
                color: isActive
                  ? "var(--db-accent)"
                  : isHovered
                  ? "var(--db-text-primary)"
                  : "var(--db-text-secondary)",
                background: isActive
                  ? "rgba(0, 212, 255, 0.07)"
                  : isHovered
                  ? "rgba(255,255,255,0.04)"
                  : "transparent",
                textShadow: isActive || isHovered
                  ? "0 0 16px rgba(0,212,255,0.5)"
                  : "none",
              }}
            >
              {tab.label}
              <span
                className="absolute bottom-0 left-0 h-[2px] rounded-full"
                style={{
                  background: "var(--db-accent)",
                  boxShadow: "0 0 8px rgba(0,212,255,0.7)",
                  width: isActive ? "100%" : "0%",
                  transition: "width 300ms cubic-bezier(0.4, 0, 0.2, 1)",
                  transformOrigin: "left",
                }}
              />
            </button>
          );
        })}
      </nav>

      {/* Mobile tab selector — visible after leaving landing */}
      {hasLeftLanding && (
        <select
          className="md:hidden text-sm rounded-lg px-3 py-1.5 outline-none"
          style={{
            background: "rgba(255,255,255,0.06)",
            border: "1px solid rgba(255,255,255,0.1)",
            color: "var(--db-text-primary)",
            transition: "opacity 300ms ease",
          }}
          value={currentScreen}
          onChange={(e) => setScreen(e.target.value as Screen)}
          aria-label="Navigation"
        >
          {NAV_TABS.map((tab) => (
            <option key={tab.id} value={tab.id} style={{ background: "#0a0e27" }}>
              {tab.label}
            </option>
          ))}
        </select>
      )}

      {/* Right: status */}
      <div
        className="hidden sm:flex items-center gap-2 text-xs px-3 py-1.5 rounded-full"
        style={{
          background: "rgba(0,212,255,0.06)",
          border: "1px solid rgba(0,212,255,0.15)",
          color: "var(--db-text-secondary)",
        }}
      >
        <span className="status-dot active" />
        <span style={{ color: "var(--db-text-primary)" }}>Aicoo Pulse</span>
        <span>Live</span>
      </div>
    </header>
  );
}

function ScreenRenderer() {
  const { currentScreen } = useScreen();
  const [visible, setVisible] = useState(true);
  const [renderedScreen, setRenderedScreen] = useState(currentScreen);

  useEffect(() => {
    if (currentScreen === renderedScreen) return;
    setVisible(false);
    const timer = setTimeout(() => {
      setRenderedScreen(currentScreen);
      setVisible(true);
    }, 180);
    return () => clearTimeout(timer);
  }, [currentScreen, renderedScreen]);

  return (
    <div
      style={{
        opacity: visible ? 1 : 0,
        transform: visible ? "translateY(0)" : "translateY(6px)",
        transition: "opacity 200ms ease, transform 200ms ease",
        minHeight: "100%",
      }}
    >
      {renderedScreen === "landing" && <Landing />}
      {renderedScreen === "prospect-chat" && <ProspectChat />}
      {renderedScreen === "account-brief" && <AccountBrief />}
      {renderedScreen === "routing" && <RoutingDecision />}
      {renderedScreen === "handoff" && <HandoffOutcome />}
      {renderedScreen === "dashboard" && <Dashboard />}
    </div>
  );
}

function Footer() {
  return (
    <footer
      className="flex-shrink-0 flex items-center justify-end px-6 py-3"
      style={{
        background: "rgba(10, 14, 39, 0.6)",
        borderTop: "1px solid rgba(255,255,255,0.04)",
      }}
    >
      <span className="text-xs" style={{ color: "var(--db-text-secondary)" }}>
        Powered by{" "}
        <span className="font-medium" style={{ color: "var(--db-accent)", opacity: 0.8 }}>
          Aicoo Pulse API
        </span>
      </span>
    </footer>
  );
}

function AppShell() {
  return (
    <div
      className="flex flex-col"
      style={{ minHeight: "100dvh", background: "var(--db-primary-dark)" }}
    >
      <Header />
      <div style={{ height: "60px", flexShrink: 0 }} />
      <main className="flex-1 overflow-y-auto overflow-x-hidden relative">
        <div
          className="pointer-events-none absolute top-0 left-0 right-0 h-[300px]"
          style={{
            background:
              "radial-gradient(ellipse 70% 50% at 50% -10%, rgba(0,212,255,0.1) 0%, transparent 70%)",
          }}
        />
        <ScreenRenderer />
      </main>
      <Footer />
    </div>
  );
}

export default function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <TooltipProvider>
        <ScreenProvider>
          <AppShell />
        </ScreenProvider>
        <Toaster />
      </TooltipProvider>
    </QueryClientProvider>
  );
}

