     6→const AICOO_BASE = "https://www.aicoo.io/api/v1";
     7→
     8→// ── Rate limiter: 10 requests/sec per IP ─────────────────────────────────────
     9→const aicooLimiter = rateLimit({
    10→  windowMs: 1_000,
    11→  max: 10,
    12→  standardHeaders: "draft-7",
    13→  legacyHeaders: false,
    14→  message: { error: "Too many requests — please slow down." },
    15→  validate: { xForwardedForHeader: false },
    16→});
    17→
    18→// ── Key helper ───────────────────────────────────────────────────────────────
    19→function getKey(): string {
    20→  const key = process.env.AICOO_API_KEY;
    21→  if (!key) throw new Error("AICOO_API_KEY is not configured");
    22→  return key;
    23→}
    24→
    25→function sanitizeKey(key: string): string {
    26→  if (key.length <= 14) return "***";
    27→  return `${key.slice(0, 10)}***${key.slice(-4)}`;
    28→}
    29→
    30→// ── Core proxy function ──────────────────────────────────────────────────────
    31→async function proxyToAicoo(
    32→  req: Request,
    33→  res: Response,
    34→  targetPath: string,
    35→  method: string,
    36→): Promise<void> {
    37→  const key = getKey();
    38→  const url = `${AICOO_BASE}${targetPath}`;
    39→  const timestamp = new Date().toISOString();
    40→  const ip =
    41→    (req.headers["x-forwarded-for"] as string)?.split(",")[0]?.trim() ??
    42→    req.ip ??
    43→    "unknown";
    44→
    45→  req.log.info(
    46→    { method, path: `/api/aicoo${targetPath}`, ip, key: sanitizeKey(key) },
    47→    `[${timestamp}] ${method} /api/aicoo${targetPath} from ${ip}`,
    48→  );
    49→
    50→  const headers: Record<string, string> = {
    51→    "Content-Type": "application/json",
    52→    Authorization: `Bearer ${key}`,
    53→  };
    54→
    55→  // Forward select headers from client
    56→  if (req.headers["accept"]) headers["Accept"] = req.headers["accept"] as string;
    57→  if (req.headers["x-request-id"])
    58→    headers["X-Request-Id"] = req.headers["x-request-id"] as string;
    59→
    60→  const fetchOptions: RequestInit = {
    61→    method,
    62→    headers,
    63→  };
    64→
    65→  if (method !== "GET" && method !== "HEAD" && req.body) {
    66→    fetchOptions.body = JSON.stringify(req.body);
    67→  }
    68→
    69→  // Append query string for GET requests
    70→  const qs = new URLSearchParams(req.query as Record<string, string>).toString();
    71→  const fullUrl = qs ? `${url}?${qs}` : url;
    72→
    73→  const upstreamRes = await fetch(fullUrl, fetchOptions);
    74→
    75→  let body: unknown;
    76→  const contentType = upstreamRes.headers.get("content-type") ?? "";
    77→  if (contentType.includes("application/json")) {
    78→    body = await upstreamRes.json();
    79→  } else {
    80→    body = { raw: await upstreamRes.text() };
    81→  }
    82→
    83→  if (upstreamRes.status === 401) {
    84→    res.status(401).json({ error: "API key is invalid or missing" });
    85→    return;
    86→  }
    87→
    88→  if (upstreamRes.status === 422) {
    89→    const msg =
    90→      typeof body === "object" &&
    91→      body !== null &&
    92→      "message" in body
    93→        ? (body as { message: unknown }).message
    94→        : body;
    95→    res.status(422).json({ error: msg });
    96→    return;
    97→  }
    98→
    99→  if (!upstreamRes.ok) {
   100→    req.log.error({ status: upstreamRes.status, path: targetPath }, "Aicoo upstream error");
   101→    res.status(upstreamRes.status >= 500 ? 500 : upstreamRes.status).json(
   102→      upstreamRes.status >= 500 ? { error: "Server error" } : body,
   103→    );
   104→    return;
   105→  }
   106→
   107→  res.status(upstreamRes.status).json(body);
   108→}
   109→
   110→// ── Error handler for async proxy ────────────────────────────────────────────
   111→function wrapAsync(
   112→  fn: (req: Request, res: Response) => Promise<void>,
   113→): (req: Request, res: Response, next: NextFunction) => void {
   114→  return (req, res, next) => {
   115→    fn(req, res).catch((err: unknown) => {
   116→      req.log.error({ err }, "Aicoo proxy error");
   117→      if (!res.headersSent) {
   118→        res.status(500).json({ error: "Server error" });
   119→      }
   120→      next(err);
   121→    });
   122→  };
   123→}
   124→
   125→// ── Named routes ─────────────────────────────────────────────────────────────
